// ============ DOMAIN — Entity + Repository INTERFACE ============
// lib/domain/entities/user.dart
class User {
  const User({required this.id, required this.name});
  final int id;
  final String name;
}

// lib/domain/repositories/user_repository.dart
abstract class UserRepository {
  Future<User> getById(int id);
  Stream<List<User>> watchAll();
  Future<void> refresh();
}

// ============ DATA — DataSources + Repository IMPL ============
// lib/data/datasources/user_remote_datasource.dart
class UserRemoteDataSource {
  UserRemoteDataSource(this._dio);
  final Dio _dio;

  Future<UserDto> fetchById(int id) async {
    final r = await _dio.get('/users/$id');
    return UserDto.fromJson(r.data);
  }

  Future<List<UserDto>> fetchAll() async {
    final r = await _dio.get('/users');
    return (r.data as List).map((e) => UserDto.fromJson(e)).toList();
  }
}

// lib/data/datasources/user_local_datasource.dart
class UserLocalDataSource {
  UserLocalDataSource(this._box);
  final Box<Map> _box;

  User? get(int id) {
    final raw = _box.get('user_$id');
    return raw == null ? null : UserDto.fromJson(Map<String,dynamic>.from(raw)).toEntity();
  }

  Future<void> put(User u) => _box.put('user_${u.id}', {'id': u.id, 'name': u.name});

  Stream<List<User>> watchAll() => _box.watch().map((_) =>
      _box.values.map((raw) => UserDto.fromJson(Map<String,dynamic>.from(raw)).toEntity()).toList());
}

// lib/data/repositories/user_repository_impl.dart — THE HEART
class UserRepositoryImpl implements UserRepository {
  UserRepositoryImpl(this._remote, this._local);
  final UserRemoteDataSource _remote;
  final UserLocalDataSource _local;

  // Cache-first: return the cached user immediately, then refresh in background.
  @override
  Future<User> getById(int id) async {
    final cached = _local.get(id);
    if (cached != null) {
      _refreshUser(id);          // fire-and-forget refresh
      return cached;
    }
    // Cache miss — fetch from network and save
    final dto = await _remote.fetchById(id);
    final user = dto.toEntity();
    await _local.put(user);
    return user;
  }

  // Reactive — UI observes the LOCAL source; refresh() writes into local,
  // which triggers a stream emission naturally.
  @override
  Stream<List<User>> watchAll() => _local.watchAll();

  @override
  Future<void> refresh() async {
    final dtos = await _remote.fetchAll();
    for (final dto in dtos) {
      await _local.put(dto.toEntity());
    }
  }

  Future<void> _refreshUser(int id) async {
    try {
      final dto = await _remote.fetchById(id);
      await _local.put(dto.toEntity());
    } catch (_) { /* silent — offline is OK, cached value already returned */ }
  }
}

